func quoteRequestStatusColor(status string) string {
	switch status {
	case "new":
		return "blue"
	case "contacted":
		return "yellow"
	case "converted":
		return "green"
	case "archived":
		return "gray"
	default:
		return "gray"
	}
}

func quoteRequestPaginationPath(statusFilter string) string {
	if statusFilter == "" {
		return "/quote-requests"
	}
	return "/quote-requests?status=" + statusFilter
}

